export namespace MavComponent {
  export function fromValue(value: number): MavComponent {
    for (const member of Object.values(MavComponent).filter((v): v is number => typeof v === 'number') as MavComponent[]) {
      if (member === value) {
        return member;
      }
    }
    return Object.values(MavComponent).find((v): v is number => typeof v === 'number') as MavComponent;
  }
}

/** These values define the type of firmware release.  These values indicate the first version or release of this type.  For example the first alpha release would be 64, the second would be 65. */
