    const min_distance = MavlinkMessage.getUint16(bytes, 4);
    const max_distance = MavlinkMessage.getUint16(bytes, 6);
    const current_distance = MavlinkMessage.getUint16(bytes, 8);
    const type_raw = MavlinkMessage.getUint8(bytes, 10);
    const type = MavDistanceSensor.fromValue(type_raw);
    const id = MavlinkMessage.getUint8(bytes, 11);
    const orientation_raw = MavlinkMessage.getUint8(bytes, 12);
    const orientation = MavSensorOrientation.fromValue(orientation_raw);
    const covariance = MavlinkMessage.getUint8(bytes, 13);
    const horizontal_fov = MavlinkMessage.getFloat32(bytes, 14);
    const vertical_fov = MavlinkMessage.getFloat32(bytes, 18);
    const quaternion = MavlinkMessage.getFloat32List(bytes, 22, 4);
