/** Request for terrain data and terrain status. See terrain protocol docs: https://mavlink.io/en/services/terrain.html */
/** TERRAIN_REQUEST */
export class TerrainRequest extends MavlinkMessage {
  static readonly MSG_ID = 133;
  static readonly CRC_EXTRA = 6;
  static readonly MAVLINK_ENCODED_LENGTH = 18;

  constructor(
    public readonly mask: number,
    public readonly lat: number,
    public readonly lon: number,
    public readonly grid_spacing: number
  ) {
    super();
  }

  /** Bitmask of requested 4x4 grids (row major 8x7 array of grids, 56 bits) */
  /** MAVLink type: uint64_t */
  /** mask */

  /** Latitude of SW corner of first grid */
  /** MAVLink type: int32_t */
  /** units: degE7 */
  /** lat */

  /** Longitude of SW corner of first grid */
  /** MAVLink type: int32_t */
  /** units: degE7 */
  /** lon */

  /** Grid spacing */
  /** MAVLink type: uint16_t */
  /** units: m */
  /** grid_spacing */

  get mavlinkMessageId(): number {
    return TerrainRequest.MSG_ID;
  }

  get mavlinkCrcExtra(): number {
    return TerrainRequest.CRC_EXTRA;
  }

  copyWith(partial: Partial<TerrainRequest>): TerrainRequest {
    return new TerrainRequest(
      partial.mask ?? this.mask,
      partial.lat ?? this.lat,
      partial.lon ?? this.lon,
      partial.grid_spacing ?? this.grid_spacing
    );
  }

  static parse(wire: Uint8Array): TerrainRequest {
    let bytes = wire;
    if (bytes.length < TerrainRequest.MAVLINK_ENCODED_LENGTH) {
      const padded = new Uint8Array(TerrainRequest.MAVLINK_ENCODED_LENGTH);
      padded.set(bytes);
      bytes = padded;
    }
    const mask = MavlinkMessage.getUint64(bytes, 0);
    const lat = MavlinkMessage.getInt32(bytes, 8);
    const lon = MavlinkMessage.getInt32(bytes, 12);
    const grid_spacing = MavlinkMessage.getUint16(bytes, 16);

    return new TerrainRequest(
      mask,
      lat,
      lon,
      grid_spacing
    );
  }

  serialize(): Uint8Array {
    const buffer = new Uint8Array(TerrainRequest.MAVLINK_ENCODED_LENGTH);
    MavlinkMessage.setUint64(buffer, 0, this.mask);
    MavlinkMessage.setInt32(buffer, 8, this.lat);
    MavlinkMessage.setInt32(buffer, 12, this.lon);
    MavlinkMessage.setUint16(buffer, 16, this.grid_spacing);
    return buffer;
  }
}

/** Terrain data sent from GCS. The lat/lon and grid_spacing must be the same as a lat/lon from a TERRAIN_REQUEST. See terrain protocol docs: https://mavlink.io/en/services/terrain.html */
/** TERRAIN_DATA */
export class TerrainData extends MavlinkMessage {
  static readonly MSG_ID = 134;
  static readonly CRC_EXTRA = 229;
  static readonly MAVLINK_ENCODED_LENGTH = 43;

  constructor(
    public readonly lat: number,
    public readonly lon: number,
    public readonly grid_spacing: number,
    public readonly data: number[],
    public readonly gridbit: number
  ) {
    super();
  }

  /** Latitude of SW corner of first grid */
  /** MAVLink type: int32_t */
  /** units: degE7 */
  /** lat */

  /** Longitude of SW corner of first grid */
  /** MAVLink type: int32_t */
  /** units: degE7 */
  /** lon */

  /** Grid spacing */
  /** MAVLink type: uint16_t */
  /** units: m */
  /** grid_spacing */

  /** Terrain data MSL */
  /** MAVLink type: int16_t[16] */
  /** units: m */
  /** data */

  /** bit within the terrain request mask */
  /** MAVLink type: uint8_t */
  /** gridbit */

  get mavlinkMessageId(): number {
    return TerrainData.MSG_ID;
  }

  get mavlinkCrcExtra(): number {
    return TerrainData.CRC_EXTRA;
  }

  copyWith(partial: Partial<TerrainData>): TerrainData {
    return new TerrainData(
      partial.lat ?? this.lat,
      partial.lon ?? this.lon,
      partial.grid_spacing ?? this.grid_spacing,
      partial.data ?? this.data,
      partial.gridbit ?? this.gridbit
    );
  }

  static parse(wire: Uint8Array): TerrainData {
    let bytes = wire;
    if (bytes.length < TerrainData.MAVLINK_ENCODED_LENGTH) {
      const padded = new Uint8Array(TerrainData.MAVLINK_ENCODED_LENGTH);
      padded.set(bytes);
      bytes = padded;
    }
    const lat = MavlinkMessage.getInt32(bytes, 0);
    const lon = MavlinkMessage.getInt32(bytes, 4);
    const grid_spacing = MavlinkMessage.getUint16(bytes, 8);
    const data = MavlinkMessage.getInt16List(bytes, 10, 16);
    const gridbit = MavlinkMessage.getUint8(bytes, 42);

    return new TerrainData(
      lat,
      lon,
      grid_spacing,
      data,
      gridbit
    );
  }

  serialize(): Uint8Array {
    const buffer = new Uint8Array(TerrainData.MAVLINK_ENCODED_LENGTH);
    MavlinkMessage.setInt32(buffer, 0, this.lat);
    MavlinkMessage.setInt32(buffer, 4, this.lon);
    MavlinkMessage.setUint16(buffer, 8, this.grid_spacing);
    MavlinkMessage.setInt16List(buffer, 10, this.data);
    MavlinkMessage.setUint8(buffer, 42, this.gridbit);
    return buffer;
  }
}

