    const x_vel = MavlinkMessage.getFloat32(bytes, 20);
    const y_vel = MavlinkMessage.getFloat32(bytes, 24);
    const z_vel = MavlinkMessage.getFloat32(bytes, 28);
    const x_pos = MavlinkMessage.getFloat32(bytes, 32);
    const y_pos = MavlinkMessage.getFloat32(bytes, 36);
    const z_pos = MavlinkMessage.getFloat32(bytes, 40);
