    MavlinkMessage.setFloat32(buffer, 24, this.y_vel);
    MavlinkMessage.setFloat32(buffer, 28, this.z_vel);
    MavlinkMessage.setFloat32(buffer, 32, this.x_pos);
    MavlinkMessage.setFloat32(buffer, 36, this.y_pos);
