    public readonly current_consumed: number,
    public readonly energy_consumed: number,
    public readonly temperature: number,
    public readonly voltages: number[],
    public readonly current_battery: number,
    public readonly id: number,
    public readonly battery_function: MavBatteryFunction,
    public readonly type: MavBatteryType,
    public readonly battery_remaining: number,
    public readonly time_remaining: number,
    public readonly charge_state: MavBatteryChargeState,
    public readonly voltages_ext: number[],
    public readonly mode: MavBatteryMode,
    public readonly fault_bitmask: number
