/** RTCM message for injecting into the onboard GPS (used for DGPS) */
/** GPS_RTCM_DATA */
export class GpsRtcmData extends MavlinkMessage {
  static readonly MSG_ID = 233;
  static readonly CRC_EXTRA = 35;
  static readonly MAVLINK_ENCODED_LENGTH = 182;

  constructor(
    public readonly flags: number,
    public readonly len: number,
    public readonly data: number[]
  ) {
    super();
  }

  /** LSB: 1 means message is fragmented, next 2 bits are the fragment ID, the remaining 5 bits are used for the sequence ID. Messages are only to be flushed to the GPS when the entire message has been reconstructed on the autopilot. The fragment ID specifies which order the fragments should be assembled into a buffer, while the sequence ID is used to detect a mismatch between different buffers. The buffer is considered fully reconstructed when either all 4 fragments are present, or all the fragments before the first fragment with a non full payload is received. This management is used to ensure that normal GPS operation doesn't corrupt RTCM data, and to recover from a unreliable transport delivery order. */
  /** MAVLink type: uint8_t */
  /** flags */

  /** data length */
  /** MAVLink type: uint8_t */
  /** units: bytes */
  /** len */

  /** RTCM message (may be fragmented) */
  /** MAVLink type: uint8_t[180] */
  /** data */

  get mavlinkMessageId(): number {
    return GpsRtcmData.MSG_ID;
  }

  get mavlinkCrcExtra(): number {
    return GpsRtcmData.CRC_EXTRA;
  }

  copyWith(partial: Partial<GpsRtcmData>): GpsRtcmData {
    return new GpsRtcmData(
      partial.flags ?? this.flags,
      partial.len ?? this.len,
      partial.data ?? this.data
    );
  }

  static parse(wire: Uint8Array): GpsRtcmData {
    let bytes = wire;
    if (bytes.length < GpsRtcmData.MAVLINK_ENCODED_LENGTH) {
      const padded = new Uint8Array(GpsRtcmData.MAVLINK_ENCODED_LENGTH);
      padded.set(bytes);
      bytes = padded;
    }
    const flags = MavlinkMessage.getUint8(bytes, 0);
    const len = MavlinkMessage.getUint8(bytes, 1);
    const data = MavlinkMessage.getUint8List(bytes, 2, 180);

    return new GpsRtcmData(
      flags,
      len,
      data
    );
  }

  serialize(): Uint8Array {
    const buffer = new Uint8Array(GpsRtcmData.MAVLINK_ENCODED_LENGTH);
    MavlinkMessage.setUint8(buffer, 0, this.flags);
    MavlinkMessage.setUint8(buffer, 1, this.len);
    MavlinkMessage.setUint8List(buffer, 2, this.data);
    return buffer;
  }
}

