  /** system id of the target */
  /** MAVLink type: uint8_t */
  /** target_system */

  /** component ID of the target */
  /** MAVLink type: uint8_t */
  /** target_component */

  /** signing key */
  /** MAVLink type: uint8_t[32] */
  /** secret_key */

