    const vx = MavlinkMessage.getFloat32(bytes, 36);
    const vy = MavlinkMessage.getFloat32(bytes, 40);
    const vz = MavlinkMessage.getFloat32(bytes, 44);
    const rollspeed = MavlinkMessage.getFloat32(bytes, 48);
    const pitchspeed = MavlinkMessage.getFloat32(bytes, 52);
    const yawspeed = MavlinkMessage.getFloat32(bytes, 56);
    const pose_covariance = MavlinkMessage.getFloat32List(bytes, 60, 21);
    const velocity_covariance = MavlinkMessage.getFloat32List(bytes, 144, 21);
