/** ISBD_LINK_STATUS */
export class IsbdLinkStatus extends MavlinkMessage {
  static readonly MSG_ID = 335;
  static readonly CRC_EXTRA = 225;
  static readonly MAVLINK_ENCODED_LENGTH = 24;

  constructor(
    public readonly timestamp: number,
    public readonly last_heartbeat: number,
    public readonly failed_sessions: number,
    public readonly successful_sessions: number,
    public readonly signal_quality: number,
    public readonly ring_pending: number,
    public readonly tx_session_pending: number,
    public readonly rx_session_pending: number
  ) {
    super();
  }

  /** Timestamp (UNIX Epoch time or time since system boot). The receiving end can infer timestamp format (since 1.1.1970 or since system boot) by checking for the magnitude of the number. */
  /** MAVLink type: uint64_t */
  /** units: us */
  /** timestamp */

  /** Timestamp of the last successful sbd session. The receiving end can infer timestamp format (since 1.1.1970 or since system boot) by checking for the magnitude of the number. */
  /** MAVLink type: uint64_t */
  /** units: us */
  /** last_heartbeat */

  /** Number of failed SBD sessions. */
  /** MAVLink type: uint16_t */
  /** failed_sessions */

  /** Number of successful SBD sessions. */
  /** MAVLink type: uint16_t */
  /** successful_sessions */

  /** Signal quality equal to the number of bars displayed on the ISU signal strength indicator. Range is 0 to 5, where 0 indicates no signal and 5 indicates maximum signal strength. */
  /** MAVLink type: uint8_t */
  /** signal_quality */

  /** 1: Ring call pending, 0: No call pending. */
  /** MAVLink type: uint8_t */
  /** ring_pending */

  /** 1: Transmission session pending, 0: No transmission session pending. */
  /** MAVLink type: uint8_t */
  /** tx_session_pending */

  /** 1: Receiving session pending, 0: No receiving session pending. */
  /** MAVLink type: uint8_t */
  /** rx_session_pending */

  get mavlinkMessageId(): number {
    return IsbdLinkStatus.MSG_ID;
  }

  get mavlinkCrcExtra(): number {
    return IsbdLinkStatus.CRC_EXTRA;
  }

  copyWith(partial: Partial<IsbdLinkStatus>): IsbdLinkStatus {
    return new IsbdLinkStatus(
      partial.timestamp ?? this.timestamp,
      partial.last_heartbeat ?? this.last_heartbeat,
      partial.failed_sessions ?? this.failed_sessions,
      partial.successful_sessions ?? this.successful_sessions,
      partial.signal_quality ?? this.signal_quality,
      partial.ring_pending ?? this.ring_pending,
      partial.tx_session_pending ?? this.tx_session_pending,
      partial.rx_session_pending ?? this.rx_session_pending
    );
  }

  static parse(wire: Uint8Array): IsbdLinkStatus {
    let bytes = wire;
    if (bytes.length < IsbdLinkStatus.MAVLINK_ENCODED_LENGTH) {
      const padded = new Uint8Array(IsbdLinkStatus.MAVLINK_ENCODED_LENGTH);
      padded.set(bytes);
      bytes = padded;
    }
    const timestamp = MavlinkMessage.getUint64(bytes, 0);
    const last_heartbeat = MavlinkMessage.getUint64(bytes, 8);
    const failed_sessions = MavlinkMessage.getUint16(bytes, 16);
    const successful_sessions = MavlinkMessage.getUint16(bytes, 18);
    const signal_quality = MavlinkMessage.getUint8(bytes, 20);
    const ring_pending = MavlinkMessage.getUint8(bytes, 21);
    const tx_session_pending = MavlinkMessage.getUint8(bytes, 22);
    const rx_session_pending = MavlinkMessage.getUint8(bytes, 23);

    return new IsbdLinkStatus(
      timestamp,
      last_heartbeat,
      failed_sessions,
      successful_sessions,
      signal_quality,
      ring_pending,
      tx_session_pending,
      rx_session_pending
    );
  }

  serialize(): Uint8Array {
    const buffer = new Uint8Array(IsbdLinkStatus.MAVLINK_ENCODED_LENGTH);
    MavlinkMessage.setUint64(buffer, 0, this.timestamp);
    MavlinkMessage.setUint64(buffer, 8, this.last_heartbeat);
    MavlinkMessage.setUint16(buffer, 16, this.failed_sessions);
    MavlinkMessage.setUint16(buffer, 18, this.successful_sessions);
    MavlinkMessage.setUint8(buffer, 20, this.signal_quality);
    MavlinkMessage.setUint8(buffer, 21, this.ring_pending);
    MavlinkMessage.setUint8(buffer, 22, this.tx_session_pending);
    MavlinkMessage.setUint8(buffer, 23, this.rx_session_pending);
    return buffer;
  }
}

/** RPM sensor data message. */
/** RAW_RPM */
export class RawRpm extends MavlinkMessage {
  static readonly MSG_ID = 339;
  static readonly CRC_EXTRA = 199;
  static readonly MAVLINK_ENCODED_LENGTH = 5;

  constructor(
    public readonly frequency: number,
    public readonly index: number
  ) {
    super();
  }

  /** Indicated rate */
  /** MAVLink type: float */
  /** units: rpm */
  /** frequency */

  /** Index of this RPM sensor (0-indexed) */
  /** MAVLink type: uint8_t */
  /** index */

  get mavlinkMessageId(): number {
    return RawRpm.MSG_ID;
  }

  get mavlinkCrcExtra(): number {
    return RawRpm.CRC_EXTRA;
  }

  copyWith(partial: Partial<RawRpm>): RawRpm {
    return new RawRpm(
      partial.frequency ?? this.frequency,
      partial.index ?? this.index
    );
  }

  static parse(wire: Uint8Array): RawRpm {
    let bytes = wire;
    if (bytes.length < RawRpm.MAVLINK_ENCODED_LENGTH) {
      const padded = new Uint8Array(RawRpm.MAVLINK_ENCODED_LENGTH);
      padded.set(bytes);
      bytes = padded;
    }
    const frequency = MavlinkMessage.getFloat32(bytes, 0);
    const index = MavlinkMessage.getUint8(bytes, 4);

    return new RawRpm(
      frequency,
      index
    );
  }

  serialize(): Uint8Array {
    const buffer = new Uint8Array(RawRpm.MAVLINK_ENCODED_LENGTH);
    MavlinkMessage.setFloat32(buffer, 0, this.frequency);
    MavlinkMessage.setUint8(buffer, 4, this.index);
    return buffer;
  }
}

/** The global position resulting from GPS and sensor fusion. */
